import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Helper function to map weather conditions to Lucide icons
function getWeatherIcon(condition: string): string {
  const lowerCondition = condition.toLowerCase();
  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) {
    return 'sun';
  } else if (lowerCondition.includes('cloudy') || lowerCondition.includes('cloud')) {
    return 'cloud';
  } else if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) {
    return 'cloud-rain';
  } else if (lowerCondition.includes('snowy') || lowerCondition.includes('snow')) {
    return 'cloud-snow';
  } else if (lowerCondition.includes('stormy') || lowerCondition.includes('storm')) {
    return 'cloud-lightning';
  } else if (lowerCondition.includes('foggy') || lowerCondition.includes('fog')) {
    return 'cloud-fog';
  } else if (lowerCondition.includes('partly')) {
    return 'cloud-sun';
  }
  return 'cloud';
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main weather card */}
        <Card shadow="lg" padding="var(--ggui-spacing-8)" radius="lg">
          <Stack gap="var(--ggui-spacing-6)" align="center">
            {/* Header with city and condition */}
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
            </Stack>

            {/* Weather icon and temperature */}
            <Stack gap="var(--ggui-spacing-4)" align="center" justify="center">
              <Tooltip content={`${props.condition} weather`} position="top"><Icon name={getWeatherIcon(props.condition)} size={80} color="var(--ggui-color-primary-600)" /></Tooltip>
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)" align="center">
                {props.temperature}°{props.unit}
              </Text>
            </Stack>

            {/* Humidity and wind info */}
            <Row gap="var(--ggui-spacing-8)" justify="center" wrap>
              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-500)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-primary-500)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Text weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} m/s</Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-day forecast strip */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="md" padding="var(--ggui-spacing-4)" radius="lg">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
              <Row gap="var(--ggui-spacing-3)" wrap>
                {props.forecast.map((day, index) => (
                  <Box
                    key={index}
                    padding="var(--ggui-spacing-3)"
                    background="var(--ggui-color-surfaceVariant)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    style={{ flex: '0 1 auto', minWidth: '100px', textAlign: 'center' }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center">
                      {day.day && (
                        <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                          {day.day}
                        </Text>
                      )}
                      {day.icon && (
                        <Tooltip content={`${day.day || 'Day'}: ${day.icon}`} position="top"><Icon name={day.icon} size={32} color="var(--ggui-color-primary-600)" /></Tooltip>
                      )}
                      {day.high !== undefined && day.low !== undefined && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {day.high}° / {day.low}°
                        </Text>
                      )}
                    </Stack>
                  </Box>
                ))}
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>

  );
}

