import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // Step tracking
  const [currentStep, setCurrentStep] = useState(1);
  const totalSteps = 5;

  // Form data
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validation helpers
  const validateEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  const validateStep1 = useCallback((): boolean => {
    let isValid = true;
    setNameError('');
    setEmailError('');

    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    }

    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email');
      isValid = false;
    }

    return isValid;
  }, [name, email, validateEmail]);

  const canProceedToNext = useCallback((): boolean => {
    switch (currentStep) {
      case 1:
        return validateStep1();
      case 2:
        return satisfaction !== '';
      case 3:
        return true; // feature selection is optional
      case 4:
        return true; // comments step is always valid
      case 5:
        return true; // review step is always valid
      default:
        return false;
    }
  }, [currentStep, name, email, satisfaction, features, validateStep1]);

  const handleNext = useCallback(() => {
    if (canProceedToNext() && currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, canProceedToNext]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  const handleSubmit = useCallback(() => {
    if (currentStep === 5) {
      submit({
        name,
        email,
        satisfaction: parseInt(satisfaction, 10),
        features,
        comments,
      });
    }
  }, [currentStep, name, email, satisfaction, features, comments, submit]);

  // Render helper for satisfaction labels with values
  const satisfactionOptions = useMemo(() => {
    return props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label: `${index + 1} - ${label}`,
    }));
  }, [props.satisfactionLabels]);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Survey Form</Heading>
          <Text variant="bodySmall">Step {currentStep} of {totalSteps}</Text>
        </Stack>

        {/* Progress bar */}
        <Progress value={currentStep} max={totalSteps} variant="default" size="md" />

        {/* Step content */}
        <Card shadow="md" padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)">

            {/* Step 1: Name and Email */}
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Your Information</Heading>
                <Input
                  label="Full Name"
                  placeholder="John Doe"
                  value={name}
                  onChange={setName}
                  error={nameError}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="john@example.com"
                  value={email}
                  onChange={setEmail}
                  error={emailError}
                  required
                />
              </Stack>
            )}

            {/* Step 2: Satisfaction Rating */}
            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>How satisfied are you?</Heading>
                <RadioGroup
                  label="Satisfaction Level"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              </Stack>
            )}

            {/* Step 3: Feature Interests */}
            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Which features interest you?</Heading>
                <Stack gap="var(--ggui-spacing-2)">
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={() => handleFeatureToggle(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {/* Step 4: Comments */}
            {currentStep === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Additional Comments</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Share any additional thoughts or feedback (optional)
                </Text>
                <TextArea
                  label="Comments"
                  placeholder="Share any additional thoughts or feedback..."
                  value={comments}
                  onChange={setComments}
                  rows={5}
                  maxLength={500}
                  showCount
                />
              </Stack>
            )}

            {/* Step 5: Final Review */}
            {currentStep === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Stack gap="var(--ggui-spacing-1)">
                  <Heading level={3}>Review Your Answers</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Please review your answers below before submitting.
                  </Text>
                </Stack>

                {/* Review summary */}
                <Stack gap="var(--ggui-spacing-3)">
                  <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name:</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface)">{name}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email:</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface)">{email}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction:</Text>
                        <Text variant="body" color="var(--ggui-color-onSurface)">
                          {satisfaction && `${satisfaction} - ${props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}`}
                        </Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="start">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features:</Text>
                        <Stack gap="var(--ggui-spacing-1)">
                          {features.length > 0 ? (
                            features.map((f) => (
                              <Badge key={f} variant="primary" size="sm">
                                {f}
                              </Badge>
                            ))
                          ) : (
                            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
                          )}
                        </Stack>
                      </Stack>
                      {comments && (
                        <Stack direction="horizontal" justify="between" align="start">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments:</Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurface)">{comments}</Text>
                        </Stack>
                      )}
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            )}
          </Stack>
        </Card>

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
            {currentStep < totalSteps && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!canProceedToNext()}
              >
                Next
              </Button>
            )}
            {currentStep === totalSteps && (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}

