// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper component: TaskCard
interface TaskCardProps {
  task: Props['tasks'][0];
  onMove: (taskId: string, newColumn: string) => void;
  onEdit: (taskId: string, title: string) => void;
  columns: Props['columns'];
}

function TaskCard({ task, onMove, onEdit, columns }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const editInputRef = useRef<HTMLInputElement>(null);

  const priorityColors: Record<string, string> = {
    low: 'var(--ggui-color-success-100)',
    medium: 'var(--ggui-color-warning-100)',
    high: 'var(--ggui-color-error-100)',
  };

  const priorityTextColors: Record<string, string> = {
    low: 'var(--ggui-color-success-700)',
    medium: 'var(--ggui-color-warning-700)',
    high: 'var(--ggui-color-error-700)',
  };

  const moveOptions = columns
    .filter(col => col.id !== task.column)
    .map(col => ({ value: col.id || '', label: col.name || '' }));

  const handleDoubleClick = () => {
    setIsEditing(true);
    setEditTitle(task.title || '');
  };

  const handleEditSave = () => {
    if (editTitle.trim()) {
      onEdit(task.id || '', editTitle);
      setIsEditing(false);
    }
  };

  const handleEditCancel = () => {
    setIsEditing(false);
    setEditTitle(task.title || '');
  };

  useEffect(() => {
    if (isEditing && editInputRef.current) {
      editInputRef.current.focus();
      editInputRef.current.select();
    }
  }, [isEditing]);

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
          {isEditing ? (
            <Stack gap="var(--ggui-spacing-1)" style={{ flex: 1 }}>
               <Input
                 label="Edit task"
                 value={editTitle}
                 onChange={setEditTitle}
                 size="sm"
                 data-testid="task-edit-input"
               />
              <Row gap="var(--ggui-spacing-1)">
                <Button size="xs" variant="primary" onClick={handleEditSave}>Save</Button>
                <Button size="xs" variant="ghost" onClick={handleEditCancel}>Cancel</Button>
              </Row>
            </Stack>
          ) : (
            <>
              <Text variant="body" color="var(--ggui-color-onSurface)" as={Clickable} onClick={handleDoubleClick} style={{ flex: 1, cursor: 'pointer', userSelect: 'none' }}>
                {task.title}
              </Text>
              <Button size="xs" variant="ghost" onClick={handleDoubleClick}>
                <Icon name="edit" size={14} />
              </Button>
            </>
          )}
        </Row>
        <Row gap="var(--ggui-spacing-2)" align="center">
          {task.priority && (
            <Badge
              size="sm"
              pill
              style={{
                backgroundColor: priorityColors[task.priority] || 'var(--ggui-color-surfaceVariant)',
                color: priorityTextColors[task.priority] || 'var(--ggui-color-onSurfaceVariant)',
              }}
            >
              {task.priority}
            </Badge>
          )}
          {task.assignee && (
            <Avatar name={task.assignee} size="sm" shape="circle" />
          )}
        </Row>
        {task.dueDate && (
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{task.dueDate}</Text>
        )}
        {moveOptions.length > 0 && (
          <Select
            label="Move to"
            value=""
            onChange={(col) => onMove(task.id || '', col)}
            options={moveOptions}
            size="sm"
          />
        )}
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // State
  const [tasks, setTasks] = useState(props.tasks);
  const [newTaskColumns, setNewTaskColumns] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high' }>>({});
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  // Sync with props on changes
  // Sync with props on changes
  useEffect(() => {
    if (taskChanged.latest?.task) {
      setTasks(prev => {
        const taskId = taskChanged.latest?.task?.id;
        const action = taskChanged.latest?.action;
        if (action === 'delete') {
          return prev.filter(t => t.id !== taskId);
        } else if (action === 'edit' || action === 'move') {
          return prev.map(t => t.id === taskId ? { ...t, ...taskChanged.latest.task } : t);
        } else if (action === 'create') {
          return [...prev, taskChanged.latest.task];
        }
        return prev;
      });
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [taskUpdate]);

  const handleAddTask = useCallback((columnId: string, title: string, priority: 'low' | 'medium' | 'high') => {
    const newTask = {
      id: `task-${Date.now()}`,
      title,
      priority,
      column: columnId,
    };
    setTasks(prev => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
    setNewTaskColumns(prev => ({ ...prev, [columnId]: { title: '', priority: 'medium' } }));
  }, [taskUpdate]);

  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || '' } });
  }, [taskUpdate, tasks]);

  // Compute column tasks
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Props['tasks']> = {};
    props.columns.forEach(col => { grouped[col.id || ''] = []; });
    tasks.forEach(task => {
      if (grouped[task.column || '']) grouped[task.column || ''].push(task);
    });
    return grouped;
  }, [tasks, props.columns]);

  const completedCount = tasks.filter(t => t.column === 'done').length;
  const totalCount = tasks.length;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        {/* Summary bar */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
          <Row justify="between" align="center">
            <Text variant="body" color="var(--ggui-color-primary-900)">
              <Text variant="body" weight="semibold">Kanban Board</Text> — {totalCount} total, {completedCount} completed
            </Text>
          </Row>
        </Box>

        {/* Columns */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns.map(col => (
            <Stack key={col.id} gap="var(--ggui-spacing-3)" style={{ minWidth: '300px', flex: 1 }}>
              {/* Column header */}
              <Row justify="between" align="center">
                <Heading level={3} color="var(--ggui-color-onSurface)">{col.name}</Heading>
                <Badge variant="default" size="sm">{tasksByColumn[col.id || '']?.length || 0}</Badge>
              </Row>

              {/* Task cards */}
              <Stack gap="var(--ggui-spacing-2)" style={{ minHeight: '200px' }}>
                {tasksByColumn[col.id || '']?.map(task => (
                   <TaskCard
                     key={task.id}
                     task={task}
                     onMove={handleMoveTask}
                     onEdit={handleEditTask}
                     columns={props.columns}
                   />
                ))}
              </Stack>

              {/* Add task form */}
              {newTaskColumns[col.id || ''] ? (
                <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" border>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Input
                      label="Task title"
                      placeholder="Enter task title"
                      value={newTaskColumns[col.id || '']?.title || ''}
                      onChange={(val) => setNewTaskColumns(prev => ({
                        ...prev,
                        [col.id || '']: { ...prev[col.id || ''], title: val }
                      }))}
                    />
                    <Select
                      label="Priority"
                      value={newTaskColumns[col.id || '']?.priority || 'medium'}
                      onChange={(val) => setNewTaskColumns(prev => ({
                        ...prev,
                        [col.id || '']: { ...prev[col.id || ''], priority: val as 'low' | 'medium' | 'high' }
                      }))}
                      options={[
                        { value: 'low', label: 'Low' },
                        { value: 'medium', label: 'Medium' },
                        { value: 'high', label: 'High' },
                      ]}
                    />
                    <Row gap="var(--ggui-spacing-2)">
                      <Button
                        variant="primary"
                        size="sm"
                        onClick={() => {
                          const title = newTaskColumns[col.id || '']?.title || '';
                          const priority = newTaskColumns[col.id || '']?.priority || 'medium';
                          if (title.trim()) handleAddTask(col.id || '', title, priority);
                        }}
                      >
                        Add
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => setNewTaskColumns(prev => {
                          const next = { ...prev };
                          delete next[col.id || ''];
                          return next;
                        })}
                      >
                        Cancel
                      </Button>
                    </Row>
                  </Stack>
                </Card>
              ) : (
                <Button
                  variant="outline"
                  size="sm"
                  fullWidth
                  onClick={() => setNewTaskColumns(prev => ({
                    ...prev,
                    [col.id || '']: { title: '', priority: 'medium' }
                  }))}
                >
                  + Add Task
                </Button>
              )}
            </Stack>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

