/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const maxQuantity = props.product.stock ?? 0;
  const isOutOfStock = maxQuantity === 0;
  const stockStatus = maxQuantity > 10 ? 'In Stock' : maxQuantity > 0 ? 'Low Stock' : 'Out of Stock';
  const stockVariant = maxQuantity > 10 ? 'success' : maxQuantity > 0 ? 'warning' : 'error';

  // Event handlers
  const handleQuantityIncrease = useCallback(() => {
    setQuantity((prev) => Math.min(prev + 1, maxQuantity));
  }, [maxQuantity]);

  const handleQuantityDecrease = useCallback(() => {
    setQuantity((prev) => Math.max(prev - 1, 1));
  }, []);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Helper function to render star rating
  const renderStars = (rating: number) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Icon
          key={i}
          name={i <= rating ? 'star' : 'star'}
          size={20}
          color={i <= rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
        />
      );
    }
    return stars;
  };

  // Helper function to format price with currency
  const formatPrice = (price: number | undefined, currency: string | undefined) => {
    if (price === undefined) return '';
    const currencySymbol = currency === 'USD' ? '$' : currency === 'EUR' ? '€' : currency === 'GBP' ? '£' : currency ?? '';
    return `${currencySymbol}${price.toFixed(2)}`;
  };

  // Tab items
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text variant="body" color="var(--ggui-color-onSurface)">
          {props.product.description || 'No description available.'}
        </Text>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: props.product.specifications && props.product.specifications.length > 0 ? (
        <Table
          columns={[
            { key: 'key', header: 'Key', render: (v) => <Text variant="body">{String(v)}</Text> },
            { key: 'value', header: 'Value', render: (v) => <Text variant="body">{String(v)}</Text> },
          ]}
          data={props.product.specifications as Array<{ key: string; value: string }>}
        />
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          No specifications available.
        </Text>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: props.product.reviews && props.product.reviews.length > 0 ? (
        <Stack gap="var(--ggui-spacing-4)">
          {(props.product.reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }>).map((review, idx) => (
            <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm">
              <Stack gap="var(--ggui-spacing-2)">
                <Row justify="between" align="center">
                  <Text variant="label" weight="semibold">
                    {review.author || 'Anonymous'}
                  </Text>
                  <Row gap="var(--ggui-spacing-1)" align="center">
                    {renderStars(review.rating ?? 0)}
                  </Row>
                </Row>
                <Text variant="body" color="var(--ggui-color-onSurface)">
                  {review.text || ''}
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {review.date || ''}
                </Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          No reviews yet.
        </Text>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Product Image, Title, Price, Rating, Stock */}
        <Row gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-6)"
            style={{ minWidth: '300px', width: '100%', maxWidth: '400px', aspectRatio: '1' }}
          >
            <Stack align="center" justify="center" style={{ height: '100%' }}>
              <Icon name="image" size={64} color="var(--ggui-color-primary-600)" />
              <Text variant="body" color="var(--ggui-color-primary-600)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                {props.product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={1} color="var(--ggui-color-onSurface)">
                {props.product.name || 'Product Name'}
              </Heading>

              {/* Price and Rating */}
              <Row gap="var(--ggui-spacing-4)" align="center">
                <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-600)">
                  {formatPrice(props.product.price, props.product.currency)}
                </Text>

                {/* Rating Stars */}
                <Row gap="var(--ggui-spacing-1)" align="center">
                  {renderStars(Math.round(props.product.rating ?? 0))}
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" style={{ marginLeft: 'var(--ggui-spacing-1)' }}>
                    ({props.product.reviewCount ?? 0} reviews)
                  </Text>
                </Row>
              </Row>
            </Stack>

            {/* Stock Status Badge */}
            <Badge variant={stockVariant} size="md">
              {stockStatus}
            </Badge>
          </Stack>
        </Row>

        {/* Middle Section: Tabs */}
        <Tabs
          items={tabItems}
          activeKey={activeTab}
          onChange={setActiveTab}
          variant="line"
          size="md"
        />

        {/* Bottom Section: Quantity Selector and Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4)">
              {/* Quantity Selector */}
              <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Quantity:
                </Text>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleQuantityDecrease}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Box
                  padding="var(--ggui-spacing-2)"
                  style={{ minWidth: '40px', textAlign: 'center' }}
                >
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">
                    {quantity}
                  </Text>
                </Box>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleQuantityIncrease}
                  disabled={quantity >= maxQuantity}
                >
                  +
                </Button>
              </Stack>

              <Spacer size="flex" />

              {/* Add to Cart Button */}
              <Button
                variant="primary"
                size="lg"
                onClick={handleAddToCart}
                disabled={isOutOfStock}
              >
                {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
              </Button>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

