import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State for input and messages
  const [inputValue, setInputValue] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Handle incoming messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator updates from stream
  useEffect(() => {
    if (typing.latest) {
      setTypingUsers((prev) => {
        const updated = new Set(prev);
        if (typing.latest!.active && typing.latest!.sender) {
          updated.add(typing.latest!.sender);
        } else if (!typing.latest!.active && typing.latest!.sender) {
          updated.delete(typing.latest!.sender);
        }
        return updated;
      });
    }
  }, [typing.latest]);

  // Handle message send
  const handleSend = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      // Add message to local list immediately
      setAllMessages((prev) => [
        ...prev,
        { sender: props.currentUser, text: inputValue, timestamp },
      ]);
      setInputValue('');
    }
  }, [inputValue, sendMessage, props.currentUser]);

  // Handle Enter key to send
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSend();
      }
    },
    [handleSend]
  );

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      if (groups.length === 0 || groups[groups.length - 1].sender !== msg.sender) {
        groups.push({ sender: msg.sender, messages: [msg] });
      } else {
        groups[groups.length - 1].messages.push(msg);
      }
    });

    return groups;
  }, [allMessages]);

  // Format timestamp to readable format
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Determine if typing users string should show
  const typingIndicatorText = typingUsers.size > 0
    ? Array.from(typingUsers).join(', ') + ' is typing...'
    : '';

  return (
    <Card
      padding="var(--ggui-spacing-4)"
      shadow="md"
      radius="lg"
      border
      style={{ display: 'flex', flexDirection: 'column', height: '600px' }}
    >
      {/* Header */}
      <Box
        paddingY="var(--ggui-spacing-3)"
        paddingX="var(--ggui-spacing-2)"
        style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}
      >
        <Row justify="between" align="center">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            <Heading level={3} style={{ margin: 0 }}>
              {props.title}
            </Heading>
            <Badge variant="primary" size="sm">
              {props.participantCount} {props.participantCount === 1 ? 'participant' : 'participants'}
            </Badge>
          </Stack>
        </Row>
      </Box>

      {/* Messages Container */}
      <Stack
        gap="var(--ggui-spacing-3)"
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: `var(--ggui-spacing-4) var(--ggui-spacing-2)`,
        }}
      >
        {groupedMessages.map((group, groupIdx) => {
          const isCurrentUser = group.sender === props.currentUser;

          return (
            <Stack
              key={groupIdx}
              gap="var(--ggui-spacing-1)"
              align={isCurrentUser ? 'end' : 'start'}
              style={{ maxWidth: '75%', alignSelf: isCurrentUser ? 'flex-end' : 'flex-start' }}
            >
              {/* Sender name for other users */}
              {!isCurrentUser && group.sender && (
                <Text
                  variant="label"
                  size="xs"
                  color="var(--ggui-color-onSurfaceVariant)"
                  style={{ paddingLeft: 'var(--ggui-spacing-2)' }}
                >
                  {group.sender}
                </Text>
              )}

              {/* Message bubbles */}
              {group.messages.map((msg, msgIdx) => (
                <Box
                  key={msgIdx}
                  padding="var(--ggui-spacing-3)"
                  background={
                    isCurrentUser
                      ? 'var(--ggui-color-primary-600)'
                      : 'var(--ggui-color-surfaceVariant)'
                  }
                  borderRadius="var(--ggui-shape-radius-lg)"
                  style={{ wordBreak: 'break-word' }}
                >
                  <Text
                    color={
                      isCurrentUser
                        ? 'var(--ggui-color-onContainer)'
                        : 'var(--ggui-color-onSurface)'
                    }
                    variant="body"
                    variant="body"
                  >
                    {msg.text}
                  </Text>
                  <Text
                    variant="caption"
                    color={
                      isCurrentUser
                        ? 'rgba(255, 255, 255, 0.7)'
                        : 'var(--ggui-color-onSurfaceVariant)'
                    }
                    style={{ marginTop: 'var(--ggui-spacing-1)' }}
                  >
                    {formatTime(msg.timestamp)}
                  </Text>
                </Box>
              ))}
            </Stack>
          );
        })}

        {/* Typing Indicator */}
        {typingIndicatorText && (
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center" role="status" aria-live="polite">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant)"
              style={{ fontStyle: 'italic' }}
            >
              {typingIndicatorText}
            </Text>
            <Spinner size={16} color="var(--ggui-color-onSurfaceVariant)" />
          </Stack>
        )}

        {/* Scroll anchor */}
        <div ref={messagesEndRef} />
      </Stack>

      {/* Input Area */}
      <Box
        paddingY="var(--ggui-spacing-3)"
        paddingX="var(--ggui-spacing-2)"
        style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}
      >
        <Row gap="var(--ggui-spacing-2)" align="end">
          <Input
            label="Message"
            placeholder="Type a message..."
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={handleKeyDown}
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            onClick={handleSend}
            disabled={!inputValue.trim()}
            leftIcon={<Icon name="send" size={18} />}
          >
            Send
          </Button>
        </Row>
      </Box>
    </Card>
  );
}

