// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion, MotionKeyframes } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Inject motion keyframe styles for flash animation
const MotionKeyframeStyles = () => (
  <style>{`
    @keyframes ggui-flash {
      0% { background-color: var(--ggui-flash-color, var(--ggui-color-primary-100)); }
      100% { background-color: var(--ggui-color-surface); }
    }
  `}</style>
);

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for displayed stocks (merged with stream updates)
  const [displayedStocks, setDisplayedStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());

  // Merge incoming stream updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      setDisplayedStocks((prev) => {
        const updated = prev.map((stock) => {
          if (stock.symbol === priceUpdate.latest?.symbol) {
            return {
              ...stock,
              price: priceUpdate.latest.price ?? stock.price,
              change: priceUpdate.latest.change ?? stock.change,
              changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });
      setLastUpdated(new Date());
      // Highlight the updated stock for animation
      if (priceUpdate.latest.symbol) {
        setHighlightedSymbols((prev) => new Set([...prev, priceUpdate.latest.symbol!]));
        setTimeout(() => {
          setHighlightedSymbols((prev) => {
            const next = new Set(prev);
            next.delete(priceUpdate.latest.symbol!);
            return next;
          });
        }, 500);
      }
    }
  }, [priceUpdate.latest]);

  // Format price with 2 decimals
  const formatPrice = (price?: number): string => {
    return price !== undefined ? `$${price.toFixed(2)}` : 'N/A';
  };

  // Determine color based on change
  const getChangeColor = (change?: number): string => {
    if (change === undefined) return 'var(--ggui-color-onSurface)';
    return change >= 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  };

  // Determine border color based on change
  const getChangeBorderColor = (change?: number): string => {
    if (change === undefined) return 'var(--ggui-color-outline)';
    return change >= 0 ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  };

  // Format last updated time
  const formatLastUpdated = (): string => {
    const now = new Date();
    const diff = Math.floor((now.getTime() - lastUpdated.getTime()) / 1000);
    if (diff < 60) return 'just now';
    if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
    return lastUpdated.toLocaleTimeString();
  };

  // Render a single stock card
  const renderStockCard = (stock: (typeof props.stocks)[0], index: number) => {
    const isHighlighted = stock.symbol && highlightedSymbols.has(stock.symbol);
    const changeColor = getChangeColor(stock.change);
    const changeBorderColor = getChangeBorderColor(stock.change);
    const changeDirection = stock.change !== undefined && stock.change >= 0 ? '▲' : '▼';

    return (
      <Card
        key={stock.symbol || index}
        as={Clickable}
        onClick={() => { /* stock card clicked */ }}
        padding="var(--ggui-spacing-4)"
        shadow="md"
        border={true}
        radius="lg"
        aria-label={`${stock.symbol || 'Unknown'} stock card showing ${stock.name || 'Unknown'} at ${formatPrice(stock.price)}`}
        role="article"
        hoverStyle={{ opacity: 0.9, boxShadow: 'var(--ggui-shape-shadow-lg)' }}
        style={{
          borderColor: changeBorderColor,
          cursor: 'pointer',
          transition: 'opacity 200ms ease-in-out, box-shadow 200ms ease-in-out',
          animation: isHighlighted
            ? 'ggui-flash 0.5s ease-out'
            : 'none',
          '--ggui-flash-color': getChangeColor(stock.change),
        } as React.CSSProperties}
      >
        <Stack gap="var(--ggui-spacing-2)" align="start">
          {/* Ticker Symbol */}
          <Heading
            level={4}
            color="var(--ggui-color-onSurface)"
            style={{ fontWeight: 'var(--ggui-font-weight-bold)' }}
          >
            {stock.symbol || 'N/A'}
          </Heading>

          {/* Company Name */}
          <Text
            variant="bodySmall"
            color="var(--ggui-color-onSurfaceVariant)"
          >
            {stock.name || 'Unknown'}
          </Text>

          {/* Price */}
          <Text
            variant="body"
            size="lg"
            weight="semibold"
            color="var(--ggui-color-onSurface)"
          >
            {formatPrice(stock.price)}
          </Text>

          {/* Change Amount and Percentage */}
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Text
              variant="body"
              color={changeColor}
              weight="medium"
            >
              {stock.change !== undefined
                ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2)
                : 'N/A'}
            </Text>
            <Text
              variant="body"
              color={changeColor}
              weight="medium"
              aria-label={stock.change !== undefined && stock.change >= 0 ? 'price up' : 'price down'}
            >
              {changeDirection}
            </Text>
            <Text
              variant="body"
              color={changeColor}
              weight="medium"
            >
              {stock.changePercent !== undefined
                ? (stock.changePercent >= 0 ? '+' : '') + stock.changePercent.toFixed(2) + '%'
                : 'N/A'}
            </Text>
          </Row>
        </Stack>
      </Card>
    );
  };

  return (
    <>
      <MotionKeyframeStyles />
      <MotionKeyframes />
      <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-6)">
          {/* Header */}
          <Stack gap="var(--ggui-spacing-2)" align="start">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Text
                variant="bodySmall"
                color="var(--ggui-color-onSurfaceVariant)"
              >
                Last Updated:&nbsp;
              </Text>
              <Text
                variant="bodySmall"
                color="var(--ggui-color-onSurfaceVariant)"
                weight="medium"
              >
                {formatLastUpdated()}
              </Text>
            </Row>
          </Stack>

          {/* Stock Cards Grid */}
          {displayedStocks && displayedStocks.length > 0 ? (
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
                gap: 'var(--ggui-spacing-4)',
                '@media (max-width: 768px)': {
                  gridTemplateColumns: '1fr',
                },
              }}
            >
              {displayedStocks.map((stock, index) => renderStockCard(stock, index))}
            </div>
          ) : (
            <Box
              padding="var(--ggui-spacing-6)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant)"
                align="center"
              >
                No stocks to display
              </Text>
            </Box>
          )}
        </Stack>
      </Container>
    </>
  );
}

