// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

const TOTAL_STEPS = 5;

const isValidEmail = (value: string) => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [nameTouched, setNameTouched] = useState<boolean>(false);
  const [emailTouched, setEmailTouched] = useState<boolean>(false);
  const [submitted, setSubmitted] = useState<boolean>(false);

  const safeFeatureOptions = Array.isArray(props.featureOptions) ? props.featureOptions : [];
  const safeSatisfactionLabels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];

  const nameError = useMemo(() => {
    if (!nameTouched && step !== 1) return '';
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name, nameTouched, step]);

  const emailError = useMemo(() => {
    if (!emailTouched && step !== 1) return '';
    if (!email.trim()) return 'Email is required.';
    if (!isValidEmail(email)) return 'Please enter a valid email address.';
    return '';
  }, [email, emailTouched, step]);

  const isStep1Valid = name.trim().length > 0 && isValidEmail(email);
  const isStep2Valid = satisfaction !== '';
  const canProceed =
    step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : step === 3 ? true : step === 4 ? true : true;

  const satisfactionOptions = useMemo(
    () =>
      safeSatisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label,
      })),
    [safeSatisfactionLabels]
  );

  const stepTitle = useMemo(() => {
    if (step === 1) return 'Basic Information';
    if (step === 2) return 'Satisfaction Rating';
    if (step === 3) return 'Feature Interests';
    if (step === 4) return 'Additional Comments';
    return 'Review & Submit';
  }, [step]);

  const handleFeatureToggle = useCallback((option: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(option)) return prev;
        return [...prev, option];
      }
      return prev.filter((item) => item !== option);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!isStep1Valid) return;
    }
    if (step === 2 && !isStep2Valid) return;
    setStep((prev) => (prev < TOTAL_STEPS ? prev + 1 : prev));
  }, [step, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction) || 0,
      features,
      comments: comments.trim(),
    };
    submit(payload);
    setSubmitted(true);
  }, [comments, email, features, name, satisfaction, submit]);

  useEffect(() => {
    if (!submitted) return;
    const timeout = setTimeout(() => setSubmitted(false), 2500);
    return () => clearTimeout(timeout);
  }, [submitted]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
        <Stack gap="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={2}>Multi-Step Survey</Heading>
            <Text color="var(--ggui-color-onSurfaceVariant)">Step {step} of {TOTAL_STEPS}: {stepTitle}</Text>
            <Progress value={(step / TOTAL_STEPS) * 100} max={100} variant="default" size="md" />
          </Stack>

          {submitted && (
            <Alert variant="success" title="Survey submitted">
              Thanks! Your responses were submitted successfully.
            </Alert>
          )}

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  setName(value);
                  if (!nameTouched) setNameTouched(true);
                }}
                required
                placeholder="Enter your full name"
                error={nameError || undefined}
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  if (!emailTouched) setEmailTouched(true);
                }}
                required
                placeholder="you@example.com"
                error={emailError || undefined}
              />
            </Stack>
          )}

          {step === 2 && (
            <RadioGroup
              label="How satisfied are you?"
              value={satisfaction}
              onChange={setSatisfaction}
              options={satisfactionOptions}
              direction="vertical"
              error={!isStep2Valid ? 'Please select a rating before continuing.' : undefined}
            />
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label">Which features interest you?</Text>
              {safeFeatureOptions.length === 0 && (
                <Alert variant="info" title="No features available">
                  There are currently no feature options to choose from.
                </Alert>
              )}
              {safeFeatureOptions.map((option) => (
                <Checkbox
                  key={option}
                  label={option}
                  checked={features.includes(option)}
                  onChange={(checked) => handleFeatureToggle(option, checked)}
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <TextArea
              label="Additional comments"
              value={comments}
              onChange={setComments}
              placeholder="Share any additional thoughts..."
              rows={6}
              maxLength={500}
              showCount
              helperText="Optional (maximum 500 characters)"
            />
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review your responses</Heading>
              <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="start">
                    <Text variant="label">Name</Text>
                    <Text>{name || '—'}</Text>
                  </Row>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Row justify="between" align="start">
                    <Text variant="label">Email</Text>
                    <Text>{email || '—'}</Text>
                  </Row>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Row justify="between" align="start">
                    <Text variant="label">Satisfaction</Text>
                    <Text>
                      {satisfaction
                        ? safeSatisfactionLabels[Number(satisfaction) - 1] || `Rating ${satisfaction}`
                        : '—'}
                    </Text>
                  </Row>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Feature interests</Text>
                    {features.length > 0 ? (
                      <Row gap="var(--ggui-spacing-2)" wrap>
                        {features.map((feature) => (
                          <Badge key={feature} variant="primary" size="sm">
                            {feature}
                          </Badge>
                        ))}
                      </Row>
                    ) : (
                      <Text color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
                    )}
                  </Stack>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label">Comments</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{comments.trim() || 'No comments provided.'}</Text>
                  </Stack>
                </Stack>
              </Card>
            </Stack>
          )}

          <Divider margin="var(--ggui-spacing-1)" />

          <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
            <Button variant="outline" disabled={step === 1} as={Clickable} onClick={handleBack}>
              Back
            </Button>
            {step < TOTAL_STEPS ? (
              <Button variant="primary" disabled={!canProceed} as={Clickable} onClick={handleNext}>
                Next
              </Button>
            ) : (
              <Button variant="primary" as={Clickable} onClick={handleSubmit}>
                Submit Survey
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

