// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string; priority?: 'low' | 'medium' | 'high' } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed
const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

const getPriorityVariant = (priority?: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' | 'default' => {
  if (priority === 'low') return 'success';
  if (priority === 'medium') return 'warning';
  if (priority === 'high') return 'error';
  return 'default';
};

const getTaskId = (task: { id?: string; title?: string }, index: number): string => {
  return task.id && task.id.length > 0 ? task.id : `task-${index}-${task.title || 'untitled'}`;
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [boardTasks, setBoardTasks] = useState<Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>>(
    props.tasks || []
  );
  const [newTaskByColumn, setNewTaskByColumn] = useState<Record<string, { open: boolean; title: string; priority: 'low' | 'medium' | 'high' }>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setBoardTasks(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incomingTask = taskChanged.latest.task;
    const incomingId = incomingTask.id || '';
    if (!incomingId) return;

    setBoardTasks((prev) => {
      const current = prev || [];
      const existingIndex = current.findIndex((t) => (t.id || '') === incomingId);
      if (taskChanged.latest?.action === 'delete') {
        return current.filter((t) => (t.id || '') !== incomingId);
      }
      if (existingIndex >= 0) {
        const next = [...current];
        next[existingIndex] = { ...next[existingIndex], ...incomingTask };
        return next;
      }
      return [...current, incomingTask];
    });
  }, [taskChanged.latest]);

  const normalizedColumns = useMemo(() => {
    return (props.columns || []).map((column, index) => ({
      id: column.id && column.id.length > 0 ? column.id : `column-${index}`,
      name: column.name || `Column ${index + 1}`
    }));
  }, [props.columns]);

  const tasksByColumn = useMemo(() => {
    const map: Record<string, Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>> = {};
    normalizedColumns.forEach((col) => {
      map[col.id] = [];
    });
    (boardTasks || []).forEach((task) => {
      const targetColumn = task.column || 'todo';
      if (!map[targetColumn]) map[targetColumn] = [];
      map[targetColumn].push(task);
    });
    return map;
  }, [boardTasks, normalizedColumns]);

  const totalTasks = (boardTasks || []).length;
  const completedColumn = normalizedColumns.find((c) => c.name.toLowerCase() === 'done' || c.id.toLowerCase() === 'done');
  const completedCount = completedColumn ? (tasksByColumn[completedColumn.id] || []).length : 0;

  const moveTask = useCallback(
    (taskId: string, nextColumn: string) => {
      setBoardTasks((prev) => (prev || []).map((task) => ((task.id || '') === taskId ? { ...task, column: nextColumn } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
    },
    [taskUpdate]
  );

  const startEditTask = useCallback((taskId: string, title?: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title || '');
  }, []);

  const saveEditTask = useCallback(
    (taskId: string) => {
      const safeTitle = editingTitle.trim();
      if (!safeTitle) return;
      setBoardTasks((prev) => (prev || []).map((task) => ((task.id || '') === taskId ? { ...task, title: safeTitle } : task)));
      taskUpdate({ action: 'edit', taskId, data: { column: ((boardTasks.find((t) => (t.id || '') === taskId)?.column) || 'todo'), title: safeTitle } });
      setEditingTaskId('');
      setEditingTitle('');
    },
    [editingTitle, taskUpdate, boardTasks]
  );

  const createTask = useCallback(
    (columnId: string) => {
      const formState = newTaskByColumn[columnId] || { open: false, title: '', priority: 'medium' as 'low' | 'medium' | 'high' };
      const safeTitle = formState.title.trim();
      if (!safeTitle) return;
      const id = `task-${Date.now()}`;
      const toDoColumn = normalizedColumns.find((c) => c.name.toLowerCase() === 'to do' || c.id.toLowerCase() === 'todo');
      const createColumn = toDoColumn ? toDoColumn.id : (normalizedColumns[0]?.id || 'todo');
      const task = {
        id,
        title: safeTitle,
        priority: formState.priority,
        assignee: '',
        column: createColumn,
        dueDate: ''
      };
      setBoardTasks((prev) => [...(prev || []), task]);
      taskUpdate({ action: 'create', taskId: id, data: { column: createColumn, title: safeTitle, priority: formState.priority } });
      setNewTaskByColumn((prev) => ({ ...prev, [columnId]: { open: false, title: '', priority: 'medium' } }));
    },
    [newTaskByColumn, taskUpdate, normalizedColumns]
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1}>Team Kanban Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Track and move tasks in real-time
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        {!normalizedColumns.length && (
          <Alert variant="warning" title="No columns configured">
            Add columns in props to render the board.
          </Alert>
        )}

        {!!normalizedColumns.length && (
          <Row gap="var(--ggui-spacing-4)" wrap>
            {normalizedColumns.map((column) => (
              <Card
                key={column.id}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
                style={{ flex: '1 1 320px', minWidth: '320px' }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                     <Heading level={2}>{column.name}</Heading>
                    <Badge variant="default">{(tasksByColumn[column.id] || []).length}</Badge>
                  </Row>
                  <Divider margin="var(--ggui-spacing-1)" />

                  <Stack gap="var(--ggui-spacing-2)">
                    {(tasksByColumn[column.id] || []).map((task, index) => {
                      const taskId = getTaskId(task, index);
                      const isEditing = editingTaskId === taskId;
                      return (
                        <Card key={taskId} padding="var(--ggui-spacing-3)" shadow="none">
                          <Stack gap="var(--ggui-spacing-2)">
                            <Row justify="between" align="center">
                              {isEditing ? (
                                <Input
                                  label="Edit task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  placeholder="Task title"
                                />
                              ) : (
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => startEditTask(taskId, task.title)}
                                  onDoubleClick={() => startEditTask(taskId, task.title)}
                                >
                                  {task.title || 'Untitled task'}
                                </Button>
                              )}
                              <Badge variant={getPriorityVariant(task.priority)}>{task.priority || 'none'}</Badge>
                            </Row>

                            <Row justify="between" align="center">
                              <Row gap="var(--ggui-spacing-2)" align="center">
                                <Avatar name={task.assignee || 'Unassigned'} size="sm" />
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.assignee || 'Unassigned'}
                                </Text>
                              </Row>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {task.dueDate ? `Due: ${task.dueDate}` : 'No due date'}
                              </Text>
                            </Row>

                            <Select
                              label="Move task"
                              value={task.column || ''}
                              onChange={(value) => moveTask(taskId, value)}
                              options={normalizedColumns.map((c) => ({ value: c.id, label: c.name }))}
                              placeholder="Select column"
                            />

                            <Row gap="var(--ggui-spacing-2)">
                              {isEditing ? (
                                <>
                                  <Button variant="primary" size="sm" onClick={() => saveEditTask(taskId)}>
                                    Save
                                  </Button>
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={() => {
                                      setEditingTaskId('');
                                      setEditingTitle('');
                                    }}
                                  >
                                    Cancel
                                  </Button>
                                </>
                              ) : (
                                <Button variant="outline" size="sm" onClick={() => startEditTask(taskId, task.title)}>
                                  Edit
                                </Button>
                              )}
                            </Row>
                          </Stack>
                        </Card>
                      );
                    })}

                    {(tasksByColumn[column.id] || []).length === 0 && (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No tasks in this column.
                      </Text>
                    )}
                  </Stack>

                  {(newTaskByColumn[column.id]?.open || false) ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskByColumn[column.id]?.title || ''}
                          onChange={(value) =>
                            setNewTaskByColumn((prev) => ({
                              ...prev,
                              [column.id]: {
                                open: true,
                                title: value,
                                priority: prev[column.id]?.priority || 'medium'
                              }
                            }))
                          }
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskByColumn[column.id]?.priority || 'medium'}
                          onChange={(value) =>
                            setNewTaskByColumn((prev) => ({
                              ...prev,
                              [column.id]: {
                                open: true,
                                title: prev[column.id]?.title || '',
                                priority: (value as 'low' | 'medium' | 'high') || 'medium'
                              }
                            }))
                          }
                          options={PRIORITY_OPTIONS}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" size="sm" onClick={() => createTask(column.id)}>
                            Create
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => setNewTaskByColumn((prev) => ({ ...prev, [column.id]: { open: false, title: '', priority: 'medium' } }))}
                          >
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="secondary"
                      size="sm"
                      onClick={() => setNewTaskByColumn((prev) => ({ ...prev, [column.id]: { open: true, title: '', priority: 'medium' } }))}
                    >
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            ))}
          </Row>
        )}
      </Stack>
    </Container>

  );
}

