const getCategoryColor = (category?: string): string => {
  if (!category) return 'var(--ggui-color-surfaceVariant)';
  return CATEGORY_COLORS[category.toLowerCase()] || 'var(--ggui-color-surfaceVariant)';
};

export default function Component(props: Props) {
