// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed
const getCurrencySymbol = (currency?: string): string => {
  if (!currency) return '$';
  const map: Record<string, string> = { USD: '$', EUR: '€', GBP: '£', JPY: '¥', INR: '₹', CAD: 'C$', AUD: 'A$' };
  return map[currency.toUpperCase()] ?? currency;
};

const clamp = (value: number, min: number, max: number): number => Math.min(max, Math.max(min, value));

const formatDate = (value: unknown): string => {
  if (typeof value === 'string' || typeof value === 'number' || value instanceof Date) {
    const d = new Date(value);
    if (!Number.isNaN(d.getTime())) return d.toLocaleDateString();
  }
  return 'N/A';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState<string>('description');
  const [quantity, setQuantity] = useState<number>(1);

  const maxStock = useMemo(() => (typeof props.product?.stock === 'number' && props.product.stock > 0 ? props.product.stock : 0), [props.product?.stock]);
  const safeRating = useMemo(() => clamp(Math.round(props.product?.rating ?? 0), 0, 5), [props.product?.rating]);
  const safeSpecifications = useMemo(() => (Array.isArray(props.product?.specifications) ? props.product.specifications : []), [props.product?.specifications]);
  const safeReviews = useMemo(() => (Array.isArray(props.product?.reviews) ? props.product.reviews : []), [props.product?.reviews]);
  const priceLabel = useMemo(() => `${getCurrencySymbol(props.product?.currency)}${(props.product?.price ?? 0).toFixed(2)}`, [props.product?.currency, props.product?.price]);
  const stockState = maxStock <= 0 ? 'out' : maxStock > 5 ? 'in' : 'low';

  useEffect(() => {
    setQuantity((prev) => {
      const maxAllowed = Math.max(1, maxStock || 1);
      return clamp(prev, 1, maxAllowed);
    });
  }, [maxStock]);

  const handleDecrement = useCallback(() => {
    setQuantity((prev) => clamp(prev - 1, 1, Math.max(1, maxStock || 1)));
  }, [maxStock]);

  const handleIncrement = useCallback(() => {
    setQuantity((prev) => clamp(prev + 1, 1, Math.max(1, maxStock || 1)));
  }, [maxStock]);

  const handleAddToCart = useCallback(() => {
    if (!props.product?.id || maxStock <= 0) return;
    addToCart({ productId: props.product.id, quantity });
  }, [addToCart, props.product?.id, quantity, maxStock]);

  const tabItems = useMemo(
    () => [
      {
        key: 'description',
        label: 'Description',
        content: (
          <Card padding="var(--ggui-spacing-4)">
            <Text color="var(--ggui-color-onSurfaceVariant)">{props.product?.description || 'No description available.'}</Text>
          </Card>
        ),
      },
      {
        key: 'specifications',
        label: 'Specifications',
        content: (
          <Card padding="var(--ggui-spacing-4)">
            {safeSpecifications.length === 0 ? (
              <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>
            ) : (
              <Table
                columns={[
                  { key: 'key', header: 'Specification' },
                  { key: 'value', header: 'Value' },
                ]}
                data={safeSpecifications.map((item, index) => {
                  if (item && typeof item === 'object' && !Array.isArray(item)) {
                    const record = item as Record<string, unknown>;
                    if (typeof record.key === 'string' || typeof record.value === 'string' || typeof record.value === 'number' || typeof record.value === 'boolean') {
                      return {
                        key: String(record.key ?? `Spec ${index + 1}`),
                        value: String(record.value ?? '—'),
                      };
                    }
                    const entries = Object.entries(record);
                    if (entries.length > 0) {
                      return { key: String(entries[0][0]), value: String(entries[0][1]) };
                    }
                  }
                  return { key: `Spec ${index + 1}`, value: String(item ?? '—') };
                })}
                bordered
                compact
                caption="Product specifications"
              />
            )}
          </Card>
        ),
      },
      {
        key: 'reviews',
        label: `Reviews (${props.product?.reviewCount ?? safeReviews.length})`,
        content: (
          <Stack gap="var(--ggui-spacing-3)">
            {safeReviews.length === 0 ? (
              <Card padding="var(--ggui-spacing-4)">
                <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
              </Card>
            ) : (
              safeReviews.map((review, index) => {
                const record = review && typeof review === 'object' && !Array.isArray(review) ? (review as Record<string, unknown>) : {};
                const author = typeof record.author === 'string' ? record.author : `User ${index + 1}`;
                const rating = clamp(typeof record.rating === 'number' ? Math.round(record.rating) : 0, 0, 5);
                const text = typeof record.text === 'string' ? record.text : 'No review text provided.';
                return (
                  <Card key={`review-${index}`} padding="var(--ggui-spacing-4)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row justify="between" align="center">
                        <Text weight="semibold">{author}</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{formatDate(record.date)}</Text>
                      </Row>
                      <Row gap="var(--ggui-spacing-1)">
                        {[1, 2, 3, 4, 5].map((star) => (
                          <Text key={`review-star-${index}-${star}`} color={star <= rating ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'} is="span">
                            {star <= rating ? '★' : '☆'}
                          </Text>
                        ))}
                      </Row>
                      <Text color="var(--ggui-color-onSurfaceVariant)">{text}</Text>
                    </Stack>
                  </Card>
                );
              })
            )}
          </Stack>
        ),
      },
    ],
    [props.product?.description, props.product?.reviewCount, safeReviews, safeSpecifications]
  );

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)">
          <Stack direction="vertical" gap="var(--ggui-spacing-6)">
            <Box
              padding="var(--ggui-spacing-6)"
              background="var(--ggui-color-primary-50)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Stack align="center" justify="center" gap="var(--ggui-spacing-2)">
                <Icon name="image" color="var(--ggui-color-primary-600)" size={32} />
                <Text align="center" weight="semibold" color="var(--ggui-color-primary-700)">
                  {props.product?.name || 'Unnamed Product'}
                </Text>
              </Stack>
            </Box>

            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={2}>{props.product?.name || 'Unnamed Product'}</Heading>
              <Text size="xl" weight="bold" color="var(--ggui-color-primary-700)">{priceLabel}</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Row gap="var(--ggui-spacing-1)" aria-label={`Rated ${safeRating} out of 5`}>
                  {[1, 2, 3, 4, 5].map((star) => (
                    <Text key={`product-star-${star}`} color={star <= safeRating ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'} is="span" aria-hidden="true">
                      {star <= safeRating ? '★' : '☆'}
                    </Text>
                  ))}
                </Row>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  ({props.product?.reviewCount ?? safeReviews.length} reviews)
                </Text>
              </Row>
              <Badge variant={stockState === 'in' ? 'success' : stockState === 'low' ? 'warning' : 'error'}>
                {stockState === 'in' ? 'In Stock' : stockState === 'low' ? 'Low Stock' : 'Out of Stock'}
              </Badge>
            </Stack>
          </Stack>
        </Card>

        <Tabs items={tabItems} activeKey={activeTab} onChange={setActiveTab} variant="line" />

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Purchase</Heading>
            <Row align="center" gap="var(--ggui-spacing-3)">
              <Text weight="medium">Quantity</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button variant="outline" size="sm" disabled={quantity <= 1 || maxStock <= 0} onClick={handleDecrement}>-</Button>
                <Input label="Quantity" type="number" value={String(quantity)} onChange={(value) => setQuantity(clamp(Number(value) || 1, 1, Math.max(1, maxStock || 1)))} />
                <Button variant="outline" size="sm" disabled={quantity >= Math.max(1, maxStock || 1) || maxStock <= 0} onClick={handleIncrement}>+</Button>
              </Row>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Available: {maxStock}
              </Text>
            </Row>
            <Button variant="primary" disabled={maxStock <= 0 || !props.product?.id} onClick={handleAddToCart}>
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

