import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed
const formatTimestamp = (value?: string): string => {
  if (!value) return '';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return '';
  return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [messageList, setMessageList] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [inputValue, setInputValue] = useState<string>('');
  const [activeTypingSender, setActiveTypingSender] = useState<string>('');
  const messageEndRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessageList(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) return;
    setMessageList((prev) => [
      ...prev,
      {
        sender: message.latest.sender,
        text: message.latest.text,
        timestamp: message.latest.timestamp,
      },
    ]);
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest) return;
    if (typing.latest.active && typing.latest.sender && typing.latest.sender !== props.currentUser) {
      setActiveTypingSender(typing.latest.sender);
      return;
    }
    setActiveTypingSender('');
  }, [typing.latest, props.currentUser]);

  useEffect(() => {
    if (!messageEndRef.current) return;
    messageEndRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
  }, [messageList.length, activeTypingSender]);

  const groupedMessages = useMemo(() => {
    const safeMessages = messageList ?? [];
    const groups: Array<{ sender: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    safeMessages.forEach((item) => {
      const sender = item.sender || 'Unknown';
      const prev = groups[groups.length - 1];
      if (prev && prev.sender === sender) {
        prev.items.push(item);
      } else {
        groups.push({ sender, items: [item] });
      }
    });
    return groups;
  }, [messageList]);

  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const now = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp: now });
    setMessageList((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp: now }]);
    setInputValue('');
  }, [inputValue, props.currentUser, sendMessage]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {activeTypingSender ? `${activeTypingSender} is typing...` : 'No one is typing'}
              </Text>
            </Stack>
            <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
          </Row>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Box
              padding="var(--ggui-spacing-2)"
              background="var(--ggui-color-surface)"
              borderRadius="var(--ggui-shape-radius-md)"
            >
              <Stack
                gap="var(--ggui-spacing-3)"
                style={{
                  maxHeight: '55vh',
                  overflowY: 'auto',
                }}
              >
                {groupedMessages.length === 0 ? (
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                    No messages yet.
                  </Text>
                ) : (
                  groupedMessages.map((group, groupIndex) => {
                    const isCurrentUser = group.sender === props.currentUser;
                    return (
                      <Stack
                        key={`${group.sender}-${groupIndex}`}
                        gap="var(--ggui-spacing-1)"
                        align={isCurrentUser ? 'end' : 'start'}
                      >
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender}</Text>
                        {group.items.map((msg, msgIndex) => (
                          <Box
                            key={`${group.sender}-${groupIndex}-${msgIndex}`}
                            padding="var(--ggui-spacing-3)"
                            background={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-600)'
                                : 'var(--ggui-color-surfaceVariant)'
                            }
                            borderRadius="var(--ggui-shape-radius-md)"
                          >
                            <Stack gap="var(--ggui-spacing-1)">
                              <Text
                                variant="body"
                                color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                              >
                                {msg.text || ''}
                              </Text>
                              <Text
                                variant="caption"
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-primary-100)'
                                    : 'var(--ggui-color-onSurfaceVariant)'
                                }
                              >
                                {formatTimestamp(msg.timestamp)}
                              </Text>
                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    );
                  })
                )}
                <Box><div ref={messageEndRef} /></Box>
              </Stack>
            </Box>

            <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

            <Row gap="var(--ggui-spacing-2)" align="end">
              <Box style={{ flex: 1 }}>
                <Input
                  label="Message"
                  placeholder="Type your message"
                  value={inputValue}
                  onChange={setInputValue}
                  onKeyDown={(event) => {
                    if (event.key === 'Enter') {
                      event.preventDefault();
                      handleSend();
                    }
                  }}
                />
              </Box>
              <Button variant="primary" disabled={!inputValue.trim()} as={Clickable} onClick={handleSend}>
                Send
              </Button>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

