type StockItem = {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
};

const formatCurrency = (value?: number) => {
  if (typeof value !== 'number' || Number.isNaN(value)) return '--';
  return `$${value.toFixed(2)}`;
};

const formatSigned = (value?: number) => {
  if (typeof value !== 'number' || Number.isNaN(value)) return '--';
  const sign = value > 0 ? '+' : value < 0 ? '' : '';
  return `${sign}${value.toFixed(2)}`;
};

const formatPercent = (value?: number) => {
  if (typeof value !== 'number' || Number.isNaN(value)) return '--';
  const sign = value > 0 ? '+' : value < 0 ? '' : '';
  return `${sign}${value.toFixed(2)}%`;
};

const getStockTone = (change?: number) => {
  if ((change ?? 0) >= 0) {
    return {
      border: 'var(--ggui-color-success-500)',
      text: 'var(--ggui-color-success-700)',
      flash: 'var(--ggui-color-success-100)',
      arrow: '▲',
    };
  }

  return {
    border: 'var(--ggui-color-error-500)',
    text: 'var(--ggui-color-error-700)',
    flash: 'var(--ggui-color-error-100)',
    arrow: '▼',
  };
};

const StockCard = ({ stock, flashTick, shouldFlash }: { stock: StockItem; flashTick: number; shouldFlash: boolean }) => {
  const tone = getStockTone(stock.change);

  return (
    <Card
      key={`${stock.symbol ?? stock.name ?? 'stock'}-${flashTick}`}
      padding="var(--ggui-spacing-4)"
      shadow="sm"
      radius="lg"
      border
