          <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">{formatCurrency(stock.price)}</Text>
          <Row justify="between" align="center">
            <Text variant="bodySmall" color={tone.text}>{formatSigned(stock.change)}</Text>
            <Row gap="var(--ggui-spacing-1)" align="center">
              <Text variant="bodySmall" color={tone.text}>{tone.arrow}</Text>
              <Text variant="bodySmall" weight="semibold" color={tone.text}>{formatPercent(stock.changePercent)}</Text>
            </Row>
          </Row>
        </Stack>
      </Box>
    </Card>
  );
};

