  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stockMap, setStockMap] = useState<Record<string, StockItem>>({});
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());

  useEffect(() => {
    const initialMap: Record<string, StockItem> = {};
    (props.stocks ?? []).forEach((stock, index) => {
      const key = stock.symbol ?? `${stock.name ?? 'stock'}-${index}`;
      initialMap[key] = stock;
    });
    setStockMap(initialMap);
  }, [props.stocks]);

  useEffect(() => {
    if (!priceUpdate.latest) return;
    const event = priceUpdate.latest;
    const key = event.symbol ?? '';
    if (!key) return;

    setStockMap((prev) => ({
      ...prev,
      [key]: {
        ...(prev[key] ?? {}),
        symbol: event.symbol ?? prev[key]?.symbol,
        price: typeof event.price === 'number' ? event.price : prev[key]?.price,
        change: typeof event.change === 'number' ? event.change : prev[key]?.change,
        changePercent: typeof event.changePercent === 'number' ? event.changePercent : prev[key]?.changePercent,
      },
    }));

    setFlashMap((prev) => ({ ...prev, [key]: (prev[key] ?? 0) + 1 }));
    setLastUpdated(new Date().toLocaleTimeString());
  }, [priceUpdate.latest]);

  useEffect(() => {
    const interval = setInterval(() => {
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  const renderedStocks = useMemo(() => {
    const keys = Object.keys(stockMap);
    if (keys.length === 0) return [];
    return keys.map((key) => ({ key, data: stockMap[key] }));
  }, [stockMap]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border>
          <Row justify="between" align="center" wrap>
            <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
            <Stack gap="var(--ggui-spacing-1)" align="end">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Last Updated</Text>
              <Box role="status" aria-live="polite" aria-atomic="true">
                <Text variant="label" color="var(--ggui-color-onSurface)" is="span">{lastUpdated}</Text>
              </Box>
              <Badge variant={marketStatus.latest?.status === 'open' ? 'success' : 'warning'}>
                {marketStatus.latest?.status ?? 'Status unavailable'}
              </Badge>
            </Stack>
          </Row>
        </Card>

        {renderedStocks.length === 0 ? (
          <Alert variant="info" title="No stocks available">
            No stock data is available yet.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={16}>
            {renderedStocks.map((entry) => (
              <Box key={entry.key} role="listitem">
                <StockCard stock={entry.data} flashTick={flashMap[entry.key] ?? 0} shouldFlash={(flashMap[entry.key] ?? 0) > 0} />
              </Box>
            ))}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





const DEFAULT_AVATARS = ['👤', '🧑‍💻', '🎨', '📊'];

const isValidEmail = (value: string): boolean => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const safeAvatarOptions = DEFAULT_AVATARS;
  const safeRoleOptions = props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other'];

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar ?? safeAvatarOptions[0] ?? '😀');
  const [role, setRole] = useState(props.initialProfile?.role ?? safeRoleOptions[0] ?? 'Developer');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    if (!safeAvatarOptions.includes(avatar)) {
      setAvatar(safeAvatarOptions[0] ?? '😀');
    }
  }, [avatar, safeAvatarOptions]);

  useEffect(() => {
    if (!safeRoleOptions.includes(role)) {
      setRole(safeRoleOptions[0] ?? 'Developer');
    }
  }, [role, safeRoleOptions]);

  const nameError = submitted && !name.trim() ? 'Name is required.' : '';
  const emailError = submitted && !email.trim()
    ? 'Email is required.'
    : submitted && !isValidEmail(email)
      ? 'Please enter a valid email address.'
      : '';

  const stepOneValid = Boolean(name.trim()) && Boolean(email.trim()) && isValidEmail(email);
  const stepTwoValid = Boolean(role);
  const canGoNext = step === 1 ? stepOneValid : stepTwoValid;
  const progressValue = (step / 3) * 100;

  const goNext = useCallback(() => {
    setSubmitted(true);
    if (step === 1 && !stepOneValid) return;
    if (step === 2 && !stepTwoValid) return;
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
    setSubmitted(false);
  }, [step, stepOneValid, stepTwoValid]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
    setSubmitted(false);
  }, []);

  const onCompleteSetup = useCallback(() => {
    setSubmitted(true);
    if (!stepOneValid || !stepTwoValid || !avatar) return;
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [stepOneValid, stepTwoValid, avatar, props, name, email, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={2}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" />
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Box
            key={step}
            style={{
              animation: 'ggui-slideInUp 300ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={nameError || undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={emailError || undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <RadioGroup
                    label="Choose Avatar"
                    value={avatar}
                    onChange={setAvatar}
                    direction="horizontal"
                    options={safeAvatarOptions.map((emoji) => ({
                      value: emoji,
                      label: emoji === '👤' ? 'Avatar: person' : emoji === '🧑‍💻' ? 'Avatar: developer' : emoji === '🎨' ? 'Avatar: designer' : 'Avatar: manager',
                    }))}
                  />
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select role"
                  options={safeRoleOptions.map((item) => ({ value: item, label: item }))}
                  required
                />
                <Toggle
                  label="Enable email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Review & Confirm</Heading>
                <Alert variant="info" title="Please verify your details">
                  Review your selections before completing setup.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row align="center" gap="var(--ggui-spacing-3)">
                      <Text variant="label">Avatar:</Text>
                      <Text size="2xl">{avatar}</Text>
                    </Row>
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Button variant="ghost" onClick={goBack} disabled={step === 1}>
              {step === 3 ? 'Go Back' : 'Back'}
            </Button>
            {step < 3 ? (
              <Button variant="primary" onClick={goNext} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={onCompleteSetup}>
                Complete Setup
              </Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
